/**
 * Reference test vectors generated by running the actual decompiled Android
 * encoding logic (WopReferenceEncoder.java). Each vector contains the exact
 * frame and bitstream output from the Java code for a given set of inputs.
 *
 * These tests verify that the TypeScript encoder produces bit-identical output
 * to the original Android app.
 */
import {
  encodeTimezone,
  encodeTime,
  encodeDate,
  assembleFrame,
  buildBitstream,
  type TransmitParams,
} from '../encoder';

// Reference vectors from Java (WopReferenceEncoder.java)
interface DstEventRef {
  season: number;
  month: number;
  day: number;
  hour: number;
}

interface ReferenceVector {
  name: string;
  isT1: boolean;
  tzShift: number;
  minuteShiftOrd: number;
  hemisphereOrd: number;
  hour: number;
  minute: number;
  second: number;
  year: number;
  month: number;
  day: number;
  dstSummer: DstEventRef | null;
  dstWinter: DstEventRef | null;
  headerBits: number[];
  tzBits: number[];
  timeBits: number[];
  dateBits: number[];
  frame: number[];
  bitstream: number[];
}

