// =============================================================================
// Individual field tests
// =============================================================================

describe('Java reference: individual field encoding', () => {
  for (const v of VECTORS) {
    test(`${v.name}: timezone bits`, () => {
      const actual = encodeTimezone(v.tzShift, v.minuteShiftOrd, v.hemisphereOrd);
      expect(actual).toEqual(v.tzBits);
    });

    test(`${v.name}: time bits`, () => {
      const actual = encodeTime(v.hour, v.minute, v.second);
      expect(actual).toEqual(v.timeBits);
    });

    test(`${v.name}: date bits`, () => {
      const actual = encodeDate(v.year, v.month, v.day);
      expect(actual).toEqual(v.dateBits);
    });
  }
});

// =============================================================================
// Frame assembly tests (pre-stuffing)
// =============================================================================

describe('Java reference: frame assembly', () => {
  for (const v of VECTORS) {
    test(`${v.name}: assembleFrame matches Java`, () => {
      const utc = new Date(Date.UTC(2000 + v.year, v.month - 1, v.day, v.hour, v.minute, v.second));
      const params: TransmitParams = {
        targetTimezone: v.isT1 ? 'T1' : 'T2',
        utcTime: utc,
        tz: {
          shiftHours: v.tzShift,
          minuteShift: v.minuteShiftOrd,
          hemisphere: v.hemisphereOrd,
          dstActive: false, // shift is already adjusted in test vectors
        },
        dstSummer: v.dstSummer ?? undefined,
        dstWinter: v.dstWinter ?? undefined,
      };
      const actual = assembleFrame(params);
      expect(actual).toEqual(v.frame);
    });
  }
});

// =============================================================================
// Full bitstream tests (with stuffing + trailing zeros)
// =============================================================================

describe('Java reference: full bitstream', () => {
  for (const v of VECTORS) {
    test(`${v.name}: buildBitstream matches Java`, () => {
      const utc = new Date(Date.UTC(2000 + v.year, v.month - 1, v.day, v.hour, v.minute, v.second));
      const params: TransmitParams = {
        targetTimezone: v.isT1 ? 'T1' : 'T2',
        utcTime: utc,
        tz: {
          shiftHours: v.tzShift,
          minuteShift: v.minuteShiftOrd,
          hemisphere: v.hemisphereOrd,
          dstActive: false,
        },
        dstSummer: v.dstSummer ?? undefined,
        dstWinter: v.dstWinter ?? undefined,
      };
      const actual = buildBitstream(params);
      expect(actual).toEqual(v.bitstream);
    });
  }
});
